from typing import List


def parse_nested_parens(paren_string: str) -> List[int]:
    groups = paren_string.split()
    result = []
    for group in groups:
        max_depth = 0
        current_depth = 0
        for char in group:
            if char == '(':
                current_depth += 1
                max_depth = max(max_depth, current_depth)
            elif char == ')':
                current_depth -= 1
                if current_depth < 0:
                    raise ValueError("Unbalanced parentheses: excess closing parenthesis")
            else:
                raise ValueError(f"Invalid character '{char}' in input")
        if current_depth != 0:
            raise ValueError("Unbalanced parentheses: missing closing parenthesis")
        result.append(max_depth)
    return result

